render.css:
.radar-container { display: flex; align-items: center; justify-content: center; margin-top: auto; margin-bottom: auto; }
.radar-grid { fill: none; stroke: var(--ct-surface-2); stroke-width: 1; }
.radar-axis { stroke: var(--ct-surface-2); stroke-width: 1; stroke-dasharray: 2 2; }
.radar-area { fill: var(--ct-text-strong); fill-opacity: 0.15; stroke: var(--ct-text-strong); stroke-width: 1.5; }
.radar-point { fill: var(--ct-text-strong); stroke: var(--ct-bg-deep); stroke-width: 1.5; }
